using UnityEngine;

public class ScriptingAnimations : MonoBehaviour
{
    private Animator animator;
    private Rigidbody2D rb;

    // Animation parameters
    private readonly string SPEED = "Speed";
    private readonly string GROUNDED = "Grounded";
    private readonly string JUMP = "Jump";
    private readonly string ATTACK = "Attack";
    private readonly string HIT = "Hit";
    private readonly string DEATH = "Death";

    // Movement
    public float moveSpeed = 5f;
    public float jumpForce = 10f;
    private bool isGrounded;
    private bool canMove = true;

    void Start()
    {
        animator = GetComponent<Animator>();
        rb = GetComponent<Rigidbody2D>();

        if (animator == null)
        {
            Debug.LogError("Animator is required!");
        }
        if (rb == null)
        {
            Debug.LogError("Rigidbody2D is required!");
        }
    }

    void Update()
    {
        if (animator == null || rb == null) return;

        // Can we move?
        if (!canMove) return;

        // Get input
        float horizontal = Input.GetAxis("Horizontal");

        // Set speed parameter
        float speed = Mathf.Abs(horizontal);
        animator.SetFloat(SPEED, speed);

        // Flip sprite based on direction
        if (horizontal != 0)
        {
            Vector3 scale = transform.localScale;
            scale.x = Mathf.Sign(horizontal) * Mathf.Abs(scale.x);
            transform.localScale = scale;
        }

        // Move
        Vector2 velocity = rb.velocity;
        velocity.x = horizontal * moveSpeed;
        rb.velocity = velocity;

        // Jump
        if (Input.GetButtonDown("Jump") && isGrounded)
        {
            rb.AddForce(Vector2.up * jumpForce, ForceMode2D.Impulse);
            animator.SetTrigger(JUMP);
            isGrounded = false;
            animator.SetBool(GROUNDED, false);
        }

        // Attack
        if (Input.GetButtonDown("Fire1"))
        {
            animator.SetTrigger(ATTACK);
            // Disable movement during attack
            StartCoroutine(DisableMovementDuringAttack());
        }
    }

    void OnCollisionEnter2D(Collision2D collision)
    {
        if (collision.gameObject.CompareTag("Ground"))
        {
            isGrounded = true;
            animator.SetBool(GROUNDED, true);
        }
    }

    // Coroutine to disable movement during attack
    System.Collections.IEnumerator DisableMovementDuringAttack()
    {
        canMove = false;

        // Wait for attack animation to finish
        yield return new WaitForSeconds(0.5f);

        canMove = true;
    }

    // Public method to trigger hit reaction
    public void TakeHit()
    {
        if (animator != null)
        {
            animator.SetTrigger(HIT);
        }
    }

    // Public method to trigger death
    public void Die()
    {
        if (animator != null)
        {
            animator.SetTrigger(DEATH);
            canMove = false;
        }
    }

    // Animation event callback
    public void OnAttackHit()
    {
        Debug.Log("Attack hit!");
        // Deal damage to enemies
    }

    // Animation event callback
    public void OnFootstep()
    {
        Debug.Log("Footstep!");
        // Play footstep sound
    }
}

